/* BLOQUEAR EXAMEN SI NO HAY SESION */
window.onload = function() {

  const name = sessionStorage.getItem("studentName");
  const inExam = sessionStorage.getItem("examInProgress");

  setLang(localStorage.getItem("examLanguage") || "en");

  if (!name || inExam !== "true") {
    sessionStorage.removeItem("examInProgress");
    document.getElementById("registerSection").style.display = "block";
    document.getElementById("examForm").style.display = "none";
    return;
  }

  document.getElementById("registerSection").style.display = "none";
  document.getElementById("examForm").style.display = "block";
};

/* REGISTRO Y SESION */
document.getElementById("registerForm").addEventListener("submit", function(e) {
  e.preventDefault();

  const name = document.getElementById("studentName").value.trim();
  const email = document.getElementById("studentEmail").value.trim();

  if (!name || !email) {
    alert("Please complete all fields");
    return;
  }

  sessionStorage.setItem("studentName", name);
  sessionStorage.setItem("studentEmail", email);
  sessionStorage.setItem("examInProgress", "true");

  document.getElementById("registerSection").style.display = "none";
  document.getElementById("examForm").style.display = "block";
});

/* SUBMIT EXAMEN */
document.getElementById("examForm").addEventListener("submit", function (e) {
  e.preventDefault();

  const answers = {
    q1: "Hyper Text Markup Language",
    q2: "<h1>",
    q3: "<p>",
    q4: "<a>",
    q5: "href",
    q6: "<img>",
    q7: "src",
    q8: "<li>",
    q9: "<ul>",
    q10: "<tr>",
    q11: "<td>",
    q12: "<form>",
    q13: "email",
    q14: "required",
    q15: "HTML version",
    q16: "<br>",
    q17: "Both",
    q18: "<strong>",
    q19: "<i>",
    q20: "<em>",
    q21: "<nav>",
    q22: "<footer>",
    q23: "<header>",
    q24: "<main>",
    q25: "<section>",
    q26: "<img>",
    q27: "<meta>",
    q28: 'target="_blank"',
    q29: "<audio>",
    q30: "<video>",
    q31: "HTML with meaning",
    q32: "<article>",
    q33: "<div>",
    q34: "<span>",
    q35: "<div>",
    q36: "data-*",
    q37: "<select>",
    q38: "<option>",
    q39: "<button>",
    q40: "password",
    q41: "<!-- -->",
    q42: "<link>",
    q43: "<body>",
    q44: "<html>",
    q45: "<title>",
    q46: "<iframe>",
    q47: "<strong>",
    q48: "<time>",
    q49: "<progress>",
    q50: "Structuring content"
  };

  let score = 0;
  let total = Object.keys(answers).length;

  for (let key in answers) {
    let selected = document.querySelector(`input[name="${key}"]:checked`);
    if (selected && selected.value === answers[key]) {
      score++;
    }
  }

  let percent = Math.round((score / total) * 100);
  showModal(score, total, percent);
});

/* SHOW MODAL */
function showModal(score, total, percent) {
  const modal = document.getElementById("resultModal");
  const certificateArea = document.getElementById("certificateArea");
  const modalScore = document.getElementById("modalScore");
  const modalTitle = document.getElementById("modalTitle");
  const modalMessage = document.getElementById("modalMessage");

  const name = sessionStorage.getItem("studentName") || "Student";

  modalScore.textContent = `${name} - Score: ${percent}% (${score}/${total})`;

  if (percent >= 80) {
    modalTitle.textContent = "Passed!";
    modalMessage.textContent = `Congratulations ${name}, you have been approved.`;

    if (certificateArea) {
      certificateArea.innerHTML =
        `<button class="certificate-btn"
		  onclick="generateCertificate('${name}', ${percent})">
		  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" 
			fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
			style="vertical-align:middle; margin-right:8px;">
			<circle cx="12" cy="8" r="6"/>
			<path d="M8 14l-2 7 6-3 6 3-2-7"/>
		  </svg>
		  Download Certificate
		</button>`
    }
  } else {
    modalTitle.textContent = "Failed";
    modalMessage.textContent = `${name}, you need at least 80% to pass. Try again.`;
    if (certificateArea) {
      certificateArea.innerHTML = "";
    }
  }

  modal.style.display = "flex";
}

/* CLOSE MODAL */
function closeModal() {
  document.getElementById("resultModal").style.display = "none";
  sessionStorage.removeItem("examInProgress");
  sessionStorage.clear();
  document.getElementById("examForm").reset();
  document.getElementById("registerSection").style.display = "block";
  document.getElementById("examForm").style.display = "none";
  window.scrollTo(0, 0);
}

/* RETRY EXAM */
function retryExam() {
  document.getElementById("resultModal").style.display = "none";
  document.getElementById("examForm").reset();
  window.scrollTo(0, 0);
}

function logout() {
  sessionStorage.clear();
  location.reload();
}

/* IDIOMA */
function setLang(lang) {
  document.querySelectorAll("[data-en]").forEach(element => {
    const translation = element.getAttribute(`data-${lang}`);
    if (translation) {
      element.textContent = translation;
    }
  });
  localStorage.setItem("examLanguage", lang);
}

/* BLOQUEO BOTON ATRAS */
history.pushState(null, null, location.href);

window.addEventListener("popstate", function () {
  if (sessionStorage.getItem("examInProgress") === "true") {
    history.pushState(null, null, location.href);
  }
});

window.addEventListener("beforeunload", function (e) {
  if (sessionStorage.getItem("examInProgress") === "true") {
    e.preventDefault();
    e.returnValue = "";
  }
});

window.addEventListener("pagehide", function () {
  sessionStorage.removeItem("examInProgress");
});

window.addEventListener("pageshow", function (event) {
  if (event.persisted) {
    sessionStorage.removeItem("examInProgress");
    location.reload();
  }
});

/* TIMER */
let timeLeft = 60 * 60;
let timerInterval;

function startTimer() {
  timerInterval = setInterval(() => {
    let minutes = Math.floor(timeLeft / 60);
    let seconds = timeLeft % 60;
    document.getElementById("timer").textContent =
      `Time: ${minutes}:${seconds < 10 ? "0" : ""}${seconds}`;
    timeLeft--;
    if (timeLeft < 0) {
      clearInterval(timerInterval);
      document.getElementById("examForm").requestSubmit();
    }
  }, 1000);
}

/* GENERAR CERTIFICADO - usando jsPDF directo, sin html2canvas */
function generateCertificate(name, percent) {

  // Verificar que jsPDF esté cargado
  if (typeof window.jspdf === "undefined") {
    alert("Error: jsPDF no está cargado. Verifica el script en el HTML.");
    return;
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });

  const W = 297;
  const H = 210;

  const blue   = [15, 61, 145];
  const orange = [255, 140, 0];
  const yellow = [255, 208, 0];
  const gray   = [220, 220, 220];

  // --- FONDO ---
  doc.setFillColor(255, 255, 255);
  doc.rect(0, 0, W, H, "F");

  // --- BORDE EXTERIOR ---
  doc.setDrawColor(...blue);
  doc.setLineWidth(3);
  doc.rect(8, 8, W - 16, H - 16);

  // --- BORDE INTERIOR delgado ---
  doc.setDrawColor(...orange);
  doc.setLineWidth(0.5);
  doc.rect(11, 11, W - 22, H - 22);

  // --- BARRA SUPERIOR (3 segmentos) ---
  doc.setFillColor(...blue);
  doc.rect(8, 8, (W - 16) * 0.45, 6, "F");
  doc.setFillColor(...orange);
  doc.rect(8 + (W - 16) * 0.45, 8, (W - 16) * 0.25, 6, "F");
  doc.setFillColor(...yellow);
  doc.rect(8 + (W - 16) * 0.70, 8, (W - 16) * 0.30, 6, "F");

  // --- BARRA INFERIOR (invertida) ---
  doc.setFillColor(...yellow);
  doc.rect(8, H - 14, (W - 16) * 0.30, 6, "F");
  doc.setFillColor(...orange);
  doc.rect(8 + (W - 16) * 0.30, H - 14, (W - 16) * 0.25, 6, "F");
  doc.setFillColor(...blue);
  doc.rect(8 + (W - 16) * 0.55, H - 14, (W - 16) * 0.45, 6, "F");

  // --- TITULO ---
  doc.setFont("helvetica", "bold");
  doc.setFontSize(24);
  doc.setTextColor(...blue);
  doc.text("CERTIFICATE OF COMPLETION", W / 2, 34, { align: "center" });

  // Lineas decorativas a los lados del titulo
  doc.setDrawColor(...blue);
  doc.setLineWidth(0.5);
  doc.line(20, 41, W / 2 - 68, 41);
  doc.line(W / 2 + 68, 41, W - 20, 41);

  // --- SUBTITULO ---
  doc.setFont("helvetica", "normal");
  doc.setFontSize(9);
  doc.setTextColor(120, 120, 120);
  doc.text("OFFICIAL HTML5 CERTIFICATION PROGRAM", W / 2, 41, { align: "center" });

  // --- LINEA SEPARADORA ---
  doc.setDrawColor(...gray);
  doc.setLineWidth(0.3);
  doc.line(20, 46, W - 20, 46);

  // --- "This is to certify that" ---
  doc.setFont("helvetica", "italic");
  doc.setFontSize(12);
  doc.setTextColor(100, 100, 100);
  doc.text("This is to certify that", W / 2, 63, { align: "center" });

  // --- NOMBRE ---
  doc.setFont("helvetica", "bold");
  doc.setFontSize(30);
  doc.setTextColor(10, 45, 110);
  doc.text(name, W / 2, 80, { align: "center" });

  // Subrayado naranja bajo el nombre
  const nameW = doc.getTextWidth(name);
  doc.setDrawColor(...orange);
  doc.setLineWidth(1.2);
  doc.line(W / 2 - nameW / 2, 83, W / 2 + nameW / 2, 83);

  // --- "has successfully completed" ---
  doc.setFont("helvetica", "normal");
  doc.setFontSize(11);
  doc.setTextColor(100, 100, 100);
  doc.text("has successfully completed the course", W / 2, 96, { align: "center" });

  // --- NOMBRE DEL CURSO ---
  doc.setFont("helvetica", "bold");
  doc.setFontSize(15);
  doc.setTextColor(...blue);
  doc.text("HTML5 Fundamentals & Structure", W / 2, 107, { align: "center" });

  // --- BADGE SCORE ---
  doc.setFillColor(...blue);
  doc.roundedRect(W / 2 - 22, 112, 44, 17, 8, 8, "F");

  doc.setFont("helvetica", "normal");
  doc.setFontSize(6.5);
  doc.setTextColor(255, 255, 255);
  doc.text("FINAL SCORE", W / 2, 118, { align: "center" });

  doc.setFont("helvetica", "bold");
  doc.setFontSize(13);
  doc.text(percent + "%", W / 2, 126, { align: "center" });

  // --- LINEA SEPARADORA FOOTER ---
  doc.setDrawColor(...gray);
  doc.setLineWidth(0.3);
  doc.line(20, 142, W - 20, 142);

  // --- FENIX CENTRAL ---
	const phoenixImg = "data:image/png;base64,";
	const imgSize = 28; // mm — ajusta el tamaño si quieres
	doc.addImage(phoenixImg, "PNG", W / 2 - imgSize / 2, 146, imgSize, imgSize);

	// ============================================================
	
	// --- TEXTO DEBAJO DEL FENIX ---
	doc.setFont("helvetica", "bold");
	doc.setFontSize(7);
	doc.setTextColor(...orange);
	doc.text("LEIMBEK WEB STUDIO", W / 2, 177, { align: "center" }); // 146 + 28 + 3 = 177

  // --- FECHA (izquierda) ---
  const date = new Date().toLocaleDateString("en-US", {
    year: "numeric", month: "long", day: "numeric"
  });
  doc.setFont("helvetica", "normal");
  doc.setFontSize(10);
  doc.setTextColor(60, 60, 60);
  doc.text(date, 75, 153, { align: "center" });

  doc.setDrawColor(...blue);
  doc.setLineWidth(0.4);
  doc.line(30, 157, 120, 157);

  doc.setFontSize(7);
  doc.setTextColor(150, 150, 150);
  doc.text("DATE ISSUED", 75, 162, { align: "center" });

  // --- CERT ID (derecha) ---
  const certId = "CERT-" + Math.random().toString(36).substring(2, 10).toUpperCase();
  doc.setFont("helvetica", "normal");
  doc.setFontSize(9);
  doc.setTextColor(60, 60, 60);
  doc.text(certId, W - 75, 153, { align: "center" });

  doc.setDrawColor(...blue);
  doc.setLineWidth(0.4);
  doc.line(W - 120, 157, W - 30, 157);

  doc.setFontSize(7);
  doc.setTextColor(150, 150, 150);
  doc.text("CERTIFICATE ID", W - 75, 162, { align: "center" });

  // --- GUARDAR ---
  doc.save("certificate_" + name.replace(/\s+/g, "_") + ".pdf");

}
